+import { createRequire } from 'module';
+const require = createRequire(import.meta.url);
+const { median, clamp } = require('./stats');
+
+describe('median', () => {
+  it('returns middle value of odd-length array', () => expect(median([3, 1, 4, 1, 5])).toBe(3));
+  it('returns average of two middle values for even-length array', () => expect(median([1, 2, 3, 4])).toBe(2.5));
+  it('returns single element', () => expect(median([7])).toBe(7));
+  it('sorts before computing', () => expect(median([5, 1, 3])).toBe(3));
+});
+
+describe('clamp', () => {
+  it('returns value when within range', () => expect(clamp(5, 1, 10)).toBe(5));
+  it('clamps to min', () => expect(clamp(-2, 1, 10)).toBe(1));
+  it('clamps to max', () => expect(clamp(15, 1, 10)).toBe(10));
+  it('handles value equal to bounds', () => {
+    expect(clamp(1, 1, 10)).toBe(1);
+    expect(clamp(10, 1, 10)).toBe(10);
+  });
+});
