@@ -0,0 +1,24 @@
+import { createRequire } from 'module';
+const require = createRequire(import.meta.url);
+const { slugify, capitalize, truncate } = require('./utils');
+
+describe('slugify', () => {
+  it('lowercases and hyphenates words', () => expect(slugify('Hello World')).toBe('hello-world'));
+  it('trims and strips symbols', () => expect(slugify('  Foo & Bar!')).toBe('foo-bar'));
+  it('leaves already-fine slugs alone', () => expect(slugify('Already-fine')).toBe('already-fine'));
+  it('collapses multiple separators', () => expect(slugify('a---b  c')).toBe('a-b-c'));
+});
+
+describe('capitalize', () => {
+  it('uppercases first letter and lowercases rest', () => expect(capitalize('hello world')).toBe('Hello world'));
+  it('handles all-caps', () => expect(capitalize('SHOUTING')).toBe('Shouting'));
+  it('returns empty string unchanged', () => expect(capitalize('')).toBe(''));
+});
+
+describe('truncate', () => {
+  it('returns string unchanged when short enough', () => expect(truncate('Hi', 10)).toBe('Hi'));
+  it('appends suffix when over limit', () => expect(truncate('Hello world', 5)).toBe('Hello...'));
+  it('cuts at word boundary, not mid-word', () => expect(truncate('Hello world', 7)).toBe('Hello...'));
+  it('uses custom suffix', () => expect(truncate('Hello world', 5, '…')).toBe('Hello…'));
+  it('falls back to hard cut when no word boundary exists', () => expect(truncate('Superlongword', 5)).toBe('Super...'));
+});
